import { Component, EventEmitter, Input, Output } from '@angular/core';

interface FaqItem {
  question: string;
  answer: string;
}

@Component({
  selector: 'app-faq-item',
  standalone: true,
  template: `
    <article class="faq-item" [class.open]="isOpen">
      <button class="faq-header" type="button" (click)="toggle.emit()" aria-expanded="{{ isOpen }}">
        <span class="question">{{ question }}</span>
        <span class="indicator">{{ isOpen ? '-' : '+' }}</span>
      </button>
      @if (isOpen) {
        <div class="faq-body">
          <p>{{ answer }}</p>
        </div>
      }
    </article>
  `,
  styles: [
    `.faq-item{border-radius:12px;background:#0b1020;border:1px solid #1f2937;overflow:hidden;}`,
    `.faq-item + .faq-item{margin-top:8px;}`,
    `.faq-header{width:100%;padding:12px 14px;background:transparent;border:none;display:flex;justify-content:space-between;align-items:center;color:#e5e7eb;cursor:pointer;font-size:14px;}`,
    `.indicator{font-weight:700;}`,
    `.faq-body{padding:0 14px 12px;font-size:13px;color:#9ca3af;}`
  ]
})
export class FaqItemComponent {
  @Input() question = '';
  @Input() answer = '';
  @Input() isOpen = false;
  @Output() toggle = new EventEmitter<void>();
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [FaqItemComponent],
  template: `
    <main class="app">
      <section class="card">
        <header class="header">
          <h1>FAQ</h1>
          <label class="switch">
            <input type="checkbox" [checked]="allowMultiple" (change)="onToggleAllowMultiple()" />
            <span>Allow multiple open</span>
          </label>
        </header>

        <div class="list">
          @for (item of faqItems; track item.question; let i = $index) {
            <app-faq-item
            [question]="item.question"
            [answer]="item.answer"
            [isOpen]="isItemOpen(i)"
            (toggle)="onItemToggle(i)">
            </app-faq-item>
          }
        </div>
      </section>
    </main>
  `,
  styles: [
    `.app{min-height:100vh;display:grid;place-items:center;background:#020617;color:#e5e7eb;padding:24px;}`,
    `.card{width:100%;max-width:520px;background:#020617;border-radius:16px;border:1px solid #1f2937;padding:20px;}`,
    `.header{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;}`,
    `.header h1{font-size:20px;margin:0;}`,
    `.switch{display:flex;align-items:center;gap:6px;font-size:12px;color:#9ca3af;}`
  ]
})
export class AppComponent {
  faqItems: FaqItem[] = [
    {
      question: 'Lorem ipsum dolor sit amet?',
      answer: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed non risus euismod, posuere justo ut, pulvinar neque.'
    },
    {
      question: 'Curabitur blandit tempus porttitor?',
      answer: 'Curabitur blandit tempus porttitor. Integer posuere erat a ante venenatis dapibus posuere velit aliquet.'
    },
    {
      question: 'Aenean lacinia bibendum nulla sed consectetur?',
      answer: 'Aenean lacinia bibendum nulla sed consectetur. Cras justo odio, dapibus ac facilisis in, egestas eget quam.'
    },
    {
      question: 'Vivamus sagittis lacus vel augue laoreet rutrum?',
      answer: 'Vivamus sagittis lacus vel augue laoreet rutrum faucibus dolor auctor. Maecenas faucibus mollis interdum.'
    }
  ];

  allowMultiple = false;
  openIndexes: number[] = [];

  isItemOpen(index: number): boolean {
    return this.openIndexes.includes(index);
  }

  onItemToggle(index: number): void {
    const currentlyOpen = this.isItemOpen(index);

    if (this.allowMultiple) {
      // Treat as a set
      this.openIndexes = currentlyOpen
        ? this.openIndexes.filter(i => i !== index)
        : [...this.openIndexes, index];
      return;
    }

    // Single-open mode
    if (currentlyOpen) {
      this.openIndexes = [];
    } else {
      this.openIndexes = [index];
    }
  }

  onToggleAllowMultiple(): void {
    this.allowMultiple = !this.allowMultiple;
    if (!this.allowMultiple && this.openIndexes.length > 1) {
      // Keep only the first open item in single-open mode
      this.openIndexes = this.openIndexes.length ? [this.openIndexes[0]] : [];
    }
  }
}
